const StyledNotificationBadge = styled("div")<{ showRipple?: boolean }>(({ showRipple }) => ({
  position: "absolute",
  width: "7px",
  height: "7px",
  backgroundColor: "#FF3333",
  borderRadius: "50%",
  ...(showRipple && {
    "&::after": {
      position: "absolute",
      top: 0,
      left: 0,
      width: "100%",
      height: "100%",
      borderRadius: "50%",
      animation: "ripple 1.2s infinite ease-in-out",
      border: "1px solid #FF3333",
      content: "\"\"",
    },
  }),
  "@keyframes ripple": {
    "0%": {
      transform: "scale(.8)",
      opacity: 1,
    },
    "100%": {
      transform: "scale(2.4)",
      opacity: 0,
    },
  },
}));

